function validatePortMappings(portMappings) {
    let usedPorts = new Set();
    let result = [];
    for (let i = 0; i < portMappings.length; i++) {
        let isValid = true;
        if (portMappings[i].exposed > 32768 || portMappings[i].host > 65535) {
            isValid = false;
        }
        if (usedPorts.has(portMappings[i].host)) {
            isValid = false;
        }
        usedPorts.add(portMappings[i].host);
        result.push(isValid);
    }
    return result;
}

