class Solution:
    def validatePortMappings(self, portMappings: list[dict[str, int]]) -> list[bool]:
        usedPorts = set()
        result = []
        for mapping in portMappings:
            isValid = True
            if mapping['exposed'] > 32768 or mapping['host'] > 65535:
                isValid = False
            if mapping['host'] in usedPorts:
                isValid = False
            usedPorts.add(mapping['host'])
            result.append(isValid)
        return result
